const express = require('express');
const helmet = require('helmet');         // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting
const { query, validationResult } = require('express-validator'); // Input validation

const app = express();

// --- Security Middleware ---
app.use(helmet());                        // Sets secure HTTP headers
app.use(express.json({ limit: '10kb' })); // Body parser with size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting — prevent brute-force / DoS
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Disable X-Powered-By (helmet does this, but being explicit)
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get(
  '/users',
  // Input validation for optional query params
  query('id').optional().isInt({ min: 1 }).withMessage('id must be a positive integer'),
  query('name').optional().isAlpha().withMessage('name must contain only letters'),
  (req, res) => {
    // Check for validation errors
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const users = [
      { id: 1, name: 'Alice' },  // Removed email — don't expose PII without auth
      { id: 2, name: 'Bob' },
    ];

    // Filter if query params provided
    let result = users;
    if (req.query.id) {
      result = result.filter((u) => u.id === parseInt(req.query.id, 10));
    }

    res.json(result);
  }
);

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler ---
// Must have 4 parameters so Express recognizes it as error middleware
app.use((err, req, res, _next) => {
  console.error('Unhandled error:', err.message); // Log internally
  res.status(err.status || 500).json({
    error: 'Internal server error',              // Generic message to client
    // NEVER send err.stack or err.message to the client in production
  });
});

// --- Server Startup ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

