const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// --- Security Middleware ---

// Set secure HTTP headers (removes X-Powered-By, adds CSP, HSTS, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload attacks
app.use(express.json({ limit: '10kb' }));

// Parse URL-encoded bodies with a size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting to mitigate brute-force and DDoS attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Request Logging ---

app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - start;
    console.log(
      `${new Date().toISOString()} ${req.method} ${req.originalUrl} ${res.statusCode} ${duration}ms`
    );
  });
  next();
});

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate optional query parameters
    const { page, limit } = req.query;

    if (page !== undefined && (isNaN(Number(page)) || Number(page) < 1)) {
      return res.status(400).json({ error: 'Invalid "page" parameter. Must be a positive integer.' });
    }
    if (limit !== undefined && (isNaN(Number(limit)) || Number(limit) < 1 || Number(limit) > 100)) {
      return res.status(400).json({ error: 'Invalid "limit" parameter. Must be between 1 and 100.' });
    }

    // In production, this would query a database
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json({ data: users, total: users.length });
  } catch (err) {
    next(err);
  }
});

// --- 404 Handler ---

app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler ---
// Must have 4 parameters so Express recognizes it as an error handler.

app.use((err, _req, res, _next) => {
  // Log the full error internally for debugging
  console.error(`[ERROR] ${new Date().toISOString()}`, err);

  // Never expose stack traces or internal details to the client
  const statusCode = err.statusCode || 500;
  res.status(statusCode).json({
    error: statusCode === 500 ? 'Internal server error' : err.message,
  });
});

// --- Server Startup ---

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

